# Automated stale bug detection — runs daily as a cron job
# Sends alerts to triage owner and engineering manager

def detect_stale_bugs(bugs):
    stale = []
    for bug in bugs:
        days_since_update = (today - bug.last_updated).days

        if bug.priority == "P1" and days_since_update > 1:
            stale.append({
                "bug": bug.id,
                "reason": f"P1 bug with no update for {days_since_update} days",
                "alert_to": [bug.owner, "engineering_manager"],
            })
        elif bug.priority == "P2" and days_since_update > 5:
            stale.append({
                "bug": bug.id,
                "reason": f"P2 bug with no update for {days_since_update} days",
                "alert_to": [bug.owner, "l3_lead"],
            })
        elif bug.priority == "P3" and days_since_update > 14:
            stale.append({
                "bug": bug.id,
                "reason": f"P3 bug with no update for {days_since_update} days",
                "alert_to": [bug.owner],
            })
        elif bug.severity in ("S1", "S2") and bug.owner is None:
            stale.append({
                "bug": bug.id,
                "reason": "S1/S2 bug with no owner assigned",
                "alert_to": ["engineering_manager", "l3_on_call"],
                "urgent": True,
            })

    return stale
